scwin.udc_ed_transDstFrom1_callBackFunc = function (ret) {
  if (!$c.gus.cfIsNull($p, ret) && ret[0] != "N/A") {
    ed_transDstFrom1.setValue(ret[0]);
    hid_transDstFromNm1.setValue(ret[1]);
    hid_transDstFromWrkPlCd1.setValue(ret[2]);
  } else {
    //ed_transDstFrom1.setValue("");                  
    //hid_transDstFromNm1.setValue(""); 
    //hid_transDstFromWrkPlCd1.setValue("");    
  }
  if (!$c.gus.cfIsNull($p, ed_transDstFrom1.getValue())) {
    // 출발지 설정
    hid_startPoint1.setValue(ed_transDstFrom1.getValue());
    if (ed_transDstFrom1.getValue() == "6P42") {
      // CY 가 울산정일부두(6P42) 인 경우 : 화주 필수 입력
      ed_mchtCd1.options.mandatory = true;
      lbl_mchtCd1.addClass("req");

      // CY 가 울산정일부두(6P42) 인 경우 : 컨테이너번호 옵션
      ed_cntrNo1.options.mandatory = false;
      lbl_cntrNo1.removeClass("req");
      ed_cntrNo1.setValue("");
    } else if (ed_transDstFrom1.getValue() == "6P14" || ed_transDstFrom1.getValue() == "6P12") {
      // CY 가 허치슨감만T(6P14)/HBCT(6P12) 인 경우 : 컨테이너번호 <- ZZZZ1234567
      ed_cntrNo1.options.mandatory = true;
      lbl_cntrNo1.addClass("req");
      ed_cntrNo1.setValue("ZZZZ1234567");
    } else if (ed_transDstFrom1.getValue() == "6P42") {
      // CY 가 울산6부두[UCTC] (6P36) 인 경우 : EMPTY
      ed_cntrNo1.options.mandatory = true;
      lbl_cntrNo1.addClass("req");
      ed_cntrNo1.setValue("EMPTY");
    } else {
      // 기타 작업장 : 컨테이너 필수 입력
      ed_cntrNo1.options.mandatory = true;
      lbl_cntrNo1.addClass("req");
    }
    if (ed_transDstFrom1.getValue() == "6P13") {
      // CY 가 PECT(6P36) 인 경우 : 샤시위치정보 필수
      acb_chassisPosInfo1.mandatory = "true";
      lbl_chassisPosInfo1.addClass("req");
    } else {
      // 기타 작업장 : 샤시위치정보 선택
      acb_chassisPosInfo1.mandatory = "false";
      lbl_chassisPosInfo1.removeClass("req");
    }
  }
  if (!$c.gus.cfIsNull($p, hid_transDstFromWrkPlCd1.getValue())) {
    if (hid_transDstFromWrkPlCd1.getValue() == DsConstants.WRK_PL_CLS_CD_PORT) {
      // CY 가 부두인 경우 : OPERATOR 필수 입력
      lbl_shpCoCd1.addClass("req");
    }
  }
  if (!$c.gus.cfIsNull($p, ed_transDstFrom1.getValue())) {
    // 수신자 <- 출발지 설정
    hid_rcv1.setValue(ed_transDstFrom1.getValue());
  } else {
    hid_rcv1.setValue("");
  }
};
